import{_ as e,o,c as t,ak as r}from"./chunks/framework.oFDsBAuP.js";const u=JSON.parse('{"title":"常见问题","description":"API 调用报错排查、网络与账号、认证权限与客户端环境说明","frontmatter":{"title":"常见问题","description":"API 调用报错排查、网络与账号、认证权限与客户端环境说明"},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),n={name:"faq.md"};function i(s,a,l,c,d,h){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="常见问题-报错指南" tabindex="-1">常见问题 &amp; 报错指南 <a class="header-anchor" href="#常见问题-报错指南" aria-label="Permalink to &quot;常见问题 &amp; 报错指南&quot;">​</a></h1><p>欢迎查阅 API 调用常见问题解答。若在使用过程中遇到下列报错，可按对应条目排查。</p><p>以下内容整理自 <a href="https://www.ddshub.cc/faq" target="_blank" rel="noreferrer">呆呆兽 Hub · 常见问题</a>，与多数基于 New API / 同类网关的部署相通；<strong>具体配额、分组与控制台路径以你当前使用的平台为准</strong>。若与上游说明不一致，以服务商最新文档为准。</p><hr><h2 id="服务端-网络连接类错误" tabindex="-1">服务端 &amp; 网络连接类错误 <a class="header-anchor" href="#服务端-网络连接类错误" aria-label="Permalink to &quot;服务端 &amp; 网络连接类错误&quot;">​</a></h2><h3 id="_502-upstream-service-temporarily-unavailable" tabindex="-1"><code>502 Upstream service temporarily unavailable</code> <a class="header-anchor" href="#_502-upstream-service-temporarily-unavailable" aria-label="Permalink to &quot;`502 Upstream service temporarily unavailable`&quot;">​</a></h3><p><strong>可能原因：</strong> 上游服务暂时不可用，或者您的网络连接不稳定；若使用的是 <strong>1M 上下文</strong>模型，也可能是单次对话上下文超过 <strong>200K</strong> 且未能自动压缩。</p><p><strong>解决方案：</strong></p><ol><li>先关闭 VPN（含 CCSwitch 等代理），稍等数分钟后重试。若网关提供状态页（如 <code>/status</code>），可访问以确认 Base URL 连通性。</li><li>检查上下文是否超过 200K。若超出，请新开会话，并改用非 1M 上下文版本的模型。</li></ol><h3 id="unable-to-connect-api-und-err-socket-或-econnreset" tabindex="-1"><code>Unable to connect API (UND_ERR_SOCKET)</code> 或 <code>(ECONNRESET)</code> <a class="header-anchor" href="#unable-to-connect-api-und-err-socket-或-econnreset" aria-label="Permalink to &quot;`Unable to connect API (UND_ERR_SOCKET)` 或 `(ECONNRESET)`&quot;">​</a></h3><p><strong>可能原因：</strong> 本地网络异常、代理节点不稳定，或被防火墙拦截。</p><p><strong>解决方案：</strong> 先排查本地网络；建议关闭 VPN 或代理后重试，或更换网络环境。</p><h3 id="unable-to-connect-api-eai-again" tabindex="-1"><code>Unable to connect API (EAI_AGAIN)</code> <a class="header-anchor" href="#unable-to-connect-api-eai-again" aria-label="Permalink to &quot;`Unable to connect API (EAI_AGAIN)`&quot;">​</a></h3><p><strong>可能原因：</strong> 本地 DNS 解析异常。</p><p><strong>解决方案：</strong> 检查本地 DNS 是否被污染。可在终端执行 <code>dig &lt;你的网关域名&gt;</code>（将占位替换为实际 API 域名）测试解析是否正常。</p><hr><h2 id="账号-并发类错误" tabindex="-1">账号 &amp; 并发类错误 <a class="header-anchor" href="#账号-并发类错误" aria-label="Permalink to &quot;账号 &amp; 并发类错误&quot;">​</a></h2><h3 id="_503-service-unavailable-或-503-no-available-accounts" tabindex="-1"><code>503 Service Unavailable</code> 或 <code>503 No available accounts</code> <a class="header-anchor" href="#_503-service-unavailable-或-503-no-available-accounts" aria-label="Permalink to &quot;`503 Service Unavailable` 或 `503 No available accounts`&quot;">​</a></h3><p><strong>可能原因：</strong> 当前时段请求量大、上游过载，或当前分组并发已达上限。</p><p><strong>解决方案：</strong> 服务可能处于满载，请稍等数分钟后重试。</p><h3 id="_429-upstream-rate-limit-exceeded-please-retry-later" tabindex="-1"><code>429 Upstream rate limit exceeded, please retry later</code> <a class="header-anchor" href="#_429-upstream-rate-limit-exceeded-please-retry-later" aria-label="Permalink to &quot;`429 Upstream rate limit exceeded, please retry later`&quot;">​</a></h3><p><strong>可能原因：</strong> 请求频率过高，触发限流。</p><p><strong>解决方案：</strong> 暂停请求，等待数分钟后以较低频率重试。</p><hr><h2 id="认证-权限类错误" tabindex="-1">认证 &amp; 权限类错误 <a class="header-anchor" href="#认证-权限类错误" aria-label="Permalink to &quot;认证 &amp; 权限类错误&quot;">​</a></h2><h3 id="_401-api-key-is-required-in-authorization-header" tabindex="-1"><code>401 API key is required in Authorization header...</code> <a class="header-anchor" href="#_401-api-key-is-required-in-authorization-header" aria-label="Permalink to &quot;`401 API key is required in Authorization header...`&quot;">​</a></h3><p><strong>可能原因：</strong> 请求未正确携带 API Key。</p><p><strong>解决方案：</strong> 检查代码或客户端配置，确保在环境变量或 <code>Authorization</code> 等请求头中正确写入 API Key。</p><h3 id="_403-api-key-is-not-assigned-to-any-group-and-cannot-be-used" tabindex="-1"><code>403 API Key is not assigned to any group and cannot be used.</code> <a class="header-anchor" href="#_403-api-key-is-not-assigned-to-any-group-and-cannot-be-used" aria-label="Permalink to &quot;`403 API Key is not assigned to any group and cannot be used.`&quot;">​</a></h3><p><strong>可能原因：</strong> API Key 未绑定到任何可用分组。</p><p><strong>解决方案：</strong> 在控制台为该密钥分配可用分组（渠道/分组策略以当前平台为准）。</p><h3 id="_429-api-key-日限额已用完" tabindex="-1"><code>429 api key 日限额已用完</code> <a class="header-anchor" href="#_429-api-key-日限额已用完" aria-label="Permalink to &quot;`429 api key 日限额已用完`&quot;">​</a></h3><p><strong>可能原因：</strong> 该 API Key 的每日调用额度已用尽。</p><p><strong>解决方案：</strong> 在控制台查看该密钥的额度与日限额，按需充值或调整限额。</p><hr><h2 id="客户端-特定环境限制" tabindex="-1">客户端 &amp; 特定环境限制 <a class="header-anchor" href="#客户端-特定环境限制" aria-label="Permalink to &quot;客户端 &amp; 特定环境限制&quot;">​</a></h2><h3 id="_503-no-available-accounts-this-group-only-allows-claude-code-clients" tabindex="-1"><code>503 No available accounts: this group only allows Claude Code clients</code> <a class="header-anchor" href="#_503-no-available-accounts-this-group-only-allows-claude-code-clients" aria-label="Permalink to &quot;`503 No available accounts: this group only allows Claude Code clients`&quot;">​</a></h3><p><strong>可能原因：</strong> 当前分组/渠道仅允许来自 <strong>Claude Code</strong> 客户端的调用。</p><p><strong>解决方案：</strong> 在 Claude Code 客户端环境中发起调用。</p><h3 id="使用-ccswitch-时出现-503-报错" tabindex="-1">使用 CCSwitch 时出现 <code>503</code> 报错 <a class="header-anchor" href="#使用-ccswitch-时出现-503-报错" aria-label="Permalink to &quot;使用 CCSwitch 时出现 `503` 报错&quot;">​</a></h3><p><strong>可能原因：</strong> 触发了「仅允许 Claude Code 客户端」类限制。</p><p><strong>解决方案：</strong> 在 Claude Code 扩展/插件环境中使用一般不受影响；请确认调用环境符合渠道要求。</p><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li>原文档站（致谢）：<a href="https://www.ddshub.cc/faq" target="_blank" rel="noreferrer">https://www.ddshub.cc/faq</a></li><li>同类网关通用说明（英文）：<a href="https://docs.newapi.pro/zh/docs/support/faq" target="_blank" rel="noreferrer">New API FAQ</a></li></ul>',45)])])}const g=e(n,[["render",i]]);export{u as __pageData,g as default};
